using System.Reflection;
using UnityEngine;
using _Project.Scripts.Core.Adaptive;

namespace _Project.Scripts.Core.Adaptive.Adapters
{
    [DisallowMultipleComponent]
    public class CatBoundsAdapter : MonoBehaviour
    {
        [SerializeField] private CatController catController;

        private static readonly BindingFlags FieldFlags = BindingFlags.Instance | BindingFlags.NonPublic;
        private static FieldInfo _limitLeftField;
        private static FieldInfo _limitRightField;

        public void Configure(CatController controller)
        {
            catController = controller;
        }

        public void Apply(AdaptiveViewProfile.ModeCatBounds settings)
        {
            if (catController == null)
            {
                return;
            }

            CacheFields();
            _limitLeftField?.SetValue(catController, settings.limitLeft);
            _limitRightField?.SetValue(catController, settings.limitRight);
        }

        private void CacheFields()
        {
            if (_limitLeftField != null)
            {
                return;
            }

            System.Type catType = typeof(CatController);
            _limitLeftField = catType.GetField("limitLeft", FieldFlags);
            _limitRightField = catType.GetField("limitRight", FieldFlags);
        }
    }
}

