using System.Reflection;
using UnityEngine;

namespace _Project.Scripts.Core.Adaptive.Adapters
{
    [DisallowMultipleComponent]
    public class InputViewportAdapter : MonoBehaviour
    {
        [SerializeField] private DualInputHandler dualInputHandler;

        private static readonly BindingFlags FieldFlags = BindingFlags.Instance | BindingFlags.NonPublic;
        private static FieldInfo _midXField;
        private static FieldInfo _halfWidthField;

        public void Configure(DualInputHandler inputHandler)
        {
            dualInputHandler = inputHandler;
        }

        [ContextMenu("Refresh Viewport Metrics")]
        public void RefreshViewportMetrics()
        {
            if (dualInputHandler == null)
            {
                return;
            }

            CacheFields();

            float halfWidth = Screen.width * 0.5f;
            _midXField?.SetValue(dualInputHandler, halfWidth);
            _halfWidthField?.SetValue(dualInputHandler, halfWidth);
        }

        private void CacheFields()
        {
            if (_midXField != null)
            {
                return;
            }

            System.Type inputType = typeof(DualInputHandler);
            _midXField = inputType.GetField("_midX", FieldFlags);
            _halfWidthField = inputType.GetField("_halfWidth", FieldFlags);
        }
    }
}

