            {
                return aspect > _landscapeThreshold ? AdaptiveViewMode.Landscape : AdaptiveViewMode.Portrait;
            }

            return aspect < _portraitThreshold ? AdaptiveViewMode.Portrait : AdaptiveViewMode.Landscape;
