using UnityEngine;
using _Project.Scripts.Core.Adaptive.Adapters;

namespace _Project.Scripts.Core.Adaptive
{
    [DisallowMultipleComponent]
    public class AdaptiveViewOrchestrator : MonoBehaviour
    {
        [Header("References")]
        [SerializeField] private AdaptiveCameraController adaptiveCameraController;
        [SerializeField] private AdaptiveViewProfile adaptiveViewProfile;
        [SerializeField] private Camera targetCamera;

        [Header("Backgrounds")]
        [SerializeField] private GameObject portraitBackground;
        [SerializeField] private GameObject landscapeBackground;
        [SerializeField] private bool autoFitBackgroundToViewport = true;
        [SerializeField, Min(1f)] private float backgroundOverscan = 1.01f;

        [Header("Adapters")]
        [SerializeField] private TileLayoutAdapter tileLayoutAdapter;
        [SerializeField] private CatBoundsAdapter leftCatBoundsAdapter;
        [SerializeField] private CatBoundsAdapter rightCatBoundsAdapter;
        [SerializeField] private InputViewportAdapter inputViewportAdapter;

        private bool _isSubscribed;
        private bool _portraitScaleCached;
        private bool _landscapeScaleCached;
        private Vector3 _portraitBaseScale = Vector3.one;
        private Vector3 _landscapeBaseScale = Vector3.one;

        private void Awake()
        {
            if (adaptiveCameraController == null)
            {
                adaptiveCameraController = GetComponent<AdaptiveCameraController>();
            }

            if (targetCamera == null)
            {
                targetCamera = GetComponent<Camera>();
            }
        }

        private void OnEnable()
        {
            BindAndApply();
        }

        private void OnDisable()
        {
            Unbind();
        }

        public void Configure(
            AdaptiveCameraController cameraController,
            AdaptiveViewProfile viewProfile,
            Camera cameraRef,
            GameObject portraitBg,
            GameObject landscapeBg,
            TileLayoutAdapter tileAdapter,
            CatBoundsAdapter leftAdapter,
            CatBoundsAdapter rightAdapter,
            InputViewportAdapter viewportAdapter)
        {
            adaptiveCameraController = cameraController;
            adaptiveViewProfile = viewProfile;
            targetCamera = cameraRef;
            portraitBackground = portraitBg;
            landscapeBackground = landscapeBg;
            tileLayoutAdapter = tileAdapter;
            leftCatBoundsAdapter = leftAdapter;
            rightCatBoundsAdapter = rightAdapter;
            inputViewportAdapter = viewportAdapter;

            BindAndApply();
        }

        public void ApplyCurrentMode()
        {
            if (adaptiveCameraController != null)
            {
                ApplyMode(adaptiveCameraController.CurrentMode);
            }
        }

        private void BindAndApply()
        {
            if (adaptiveCameraController == null)
            {
                return;
            }

            if (!_isSubscribed)
            {
                adaptiveCameraController.OnViewModeChanged += ApplyMode;
                _isSubscribed = true;
            }

            ApplyMode(adaptiveCameraController.CurrentMode);
        }

        private void Unbind()
        {
            if (!_isSubscribed || adaptiveCameraController == null)
            {
                return;
            }

            adaptiveCameraController.OnViewModeChanged -= ApplyMode;
            _isSubscribed = false;
        }

        private void ApplyMode(AdaptiveViewMode mode)
        {
            ApplyCamera(mode);
            ApplyBackgrounds(mode);
            ApplyGameplayLayout(mode);
        }

        private void ApplyBackgrounds(AdaptiveViewMode mode)
        {
            bool isLandscape = mode == AdaptiveViewMode.Landscape;

            if (portraitBackground != null)
            {
                portraitBackground.SetActive(!isLandscape);
            }

            if (landscapeBackground != null)
            {
                landscapeBackground.SetActive(isLandscape);
            }

            if (!autoFitBackgroundToViewport)
            {
                return;
            }

            FitBackgroundToViewport(portraitBackground, ref _portraitScaleCached, ref _portraitBaseScale);
            FitBackgroundToViewport(landscapeBackground, ref _landscapeScaleCached, ref _landscapeBaseScale);
        }

        private void ApplyCamera(AdaptiveViewMode mode)
        {
            if (adaptiveViewProfile == null || targetCamera == null)
            {
                return;
            }

            AdaptiveViewProfile.ModeCameraSettings cameraSettings = adaptiveViewProfile.GetCamera(mode);
            targetCamera.orthographicSize = cameraSettings.orthographicSize;
            targetCamera.transform.localPosition = cameraSettings.localPosition;
        }

        private void FitBackgroundToViewport(GameObject background, ref bool hasCachedScale, ref Vector3 baseScale)
        {
            if (background == null || targetCamera == null || !targetCamera.orthographic)
            {
                return;
            }

            SpriteRenderer spriteRenderer = background.GetComponent<SpriteRenderer>();
            if (spriteRenderer == null || spriteRenderer.sprite == null)
            {
                return;
            }

            Transform bgTransform = background.transform;
            if (!hasCachedScale)
            {
                baseScale = bgTransform.localScale;
                hasCachedScale = true;
            }

            Vector2 spriteSize = spriteRenderer.sprite.bounds.size;
            if (spriteSize.x <= 0.0001f || spriteSize.y <= 0.0001f)
            {
                return;
            }

            float viewportHeight = targetCamera.orthographicSize * 2f;
            float viewportWidth = viewportHeight * targetCamera.aspect;

            float scaleX = viewportWidth / spriteSize.x;
            float scaleY = viewportHeight / spriteSize.y;
            float coverScale = Mathf.Max(scaleX, scaleY) * backgroundOverscan;

            bgTransform.localScale = new Vector3(
                baseScale.x * coverScale,
                baseScale.y * coverScale,
                baseScale.z);
        }

        private void ApplyGameplayLayout(AdaptiveViewMode mode)
        {
            if (adaptiveViewProfile != null)
            {
                AdaptiveViewProfile.ModeTileSettings tiles = adaptiveViewProfile.GetTiles(mode);
                tileLayoutAdapter?.Apply(tiles);

                AdaptiveViewProfile.ModeCatBounds leftBounds = adaptiveViewProfile.GetLeftCatBounds(mode);
                AdaptiveViewProfile.ModeCatBounds rightBounds = adaptiveViewProfile.GetRightCatBounds(mode);
                leftCatBoundsAdapter?.Apply(leftBounds);
                rightCatBoundsAdapter?.Apply(rightBounds);
            }

            inputViewportAdapter?.RefreshViewportMetrics();
        }
    }
}

using UnityEngine;
