using System;
using UnityEngine;

namespace _Project.Scripts.Core.Gameplay.Tile
{
    [CreateAssetMenu(fileName = "TileSpriteConfig", menuName = "DuetCats/Tile Sprite Config")]
    public class TileSpriteConfig : ScriptableObject
    {
        [Serializable]
        public struct LaneSprites
        {
            public Sprite normal;
            public Sprite rapid;
            public Sprite strong;
            public Sprite breakSprite;

            public Sprite Get(TileSprite tileSprite)
            {
                switch (tileSprite)
                {
                    case TileSprite.Rapid:
                        return rapid;
                    case TileSprite.Strong:
                        return strong;
                    case TileSprite.Break:
                        return breakSprite;
                    default:
                        return normal;
                }
            }
        }

        [Header("Lane Sprite Sets")]
        [SerializeField] private LaneSprites left;
        [SerializeField] private LaneSprites right;

        [Header("Score Rules")]
        [SerializeField] private int normalScore = 2;
        [SerializeField] private int rapidScore = 2;
        [SerializeField] private int strongScore = 10;
        [SerializeField] private int breakScore = 0;

        public Sprite GetSprite(bool isLeft, TileSprite tileSprite)
        {
            return isLeft ? left.Get(tileSprite) : right.Get(tileSprite);
        }

        public int GetScore(TileSprite tileSprite)
        {
            switch (tileSprite)
            {
                case TileSprite.Strong:
                    return strongScore;
                case TileSprite.Rapid:
                    return rapidScore;
                case TileSprite.Break:
                    return breakScore;
                default:
                    return normalScore;
            }
        }
    }
}

using System;
using UnityEngine;

namespace _Project.Scripts.Core.Gameplay.Tile
{
    [CreateAssetMenu(fileName = "TileSpriteConfig", menuName = "DuetCats/Tile Sprite Config")]
    public class TileSpriteConfig : ScriptableObject
    {
        [Serializable]
        public struct LaneSprites
        {
            public Sprite normal;
            public Sprite rapid;
            public Sprite strong;
            public Sprite breakSprite;

            public Sprite Get(TileSprite tileSprite)
            {
                switch (tileSprite)
                {
                    case TileSprite.Rapid:
                        return rapid;
                    case TileSprite.Strong:
                        return strong;
                    case TileSprite.Break:
                        return breakSprite;
                    default:
                        return normal;
                }
            }
        }

        [Header("Lane Sprite Sets")]
        [SerializeField] private LaneSprites _left;
        [SerializeField] private LaneSprites _right;

        [Header("Score Rules")]
        [SerializeField] private int _normalScore = 2;
        [SerializeField] private int _rapidScore = 2;
        [SerializeField] private int _strongScore = 10;
        [SerializeField] private int _breakScore = 0;

        public Sprite GetSprite(bool isLeft, TileSprite tileSprite)
        {
            return isLeft ? _left.Get(tileSprite) : _right.Get(tileSprite);
        }

        public int GetScore(TileSprite tileSprite)
        {
            switch (tileSprite)
            {
                case TileSprite.Strong:
                    return _strongScore;
                case TileSprite.Rapid:
                    return _rapidScore;
                case TileSprite.Break:
                    return _breakScore;
                default:
                    return _normalScore;
            }
        }
    }
}

using System.Collections.Generic;
using UnityEngine;

public class DualInputHandler : MonoBehaviour
{
    [Header("Refs")]
    [SerializeField] private CatController leftCat;
    [SerializeField] private CatController rightCat;

    [Header("Config")]
    [SerializeField] private float deadZone = 30f;

    private Dictionary<int, InputSide> fingerSides = new();

    private Dictionary<int, float> lastPosX = new();

    private float _midX;
    private float _halfWidth;

    private void Awake()
    {
        _midX = Screen.width * 0.5f;
        _halfWidth = Screen.width * 0.5f;
    }

    private void Update()
    {
        HandleMouse();
    }

    private void HandleMouse()
    {
        if (Input.GetMouseButtonDown(0))
            AssignFinger(0, Input.mousePosition.x);

        if (Input.GetMouseButton(0))
            UpdateFinger(0, Input.mousePosition.x);

        if (Input.GetMouseButtonUp(0))
            fingerSides.Remove(0);
    }

    private void AssignFinger(int id, float x)
    {
        if (x < _midX - deadZone)
            fingerSides[id] = InputSide.Left;
        else if (x > _midX + deadZone)
            fingerSides[id] = InputSide.Right;

        lastPosX[id] = x;
    }

    private void UpdateFinger(int id, float x)
    {
        if (!fingerSides.TryGetValue(id, out var side)) return;

        float deltaX = x - lastPosX[id];
        lastPosX[id] = x;

        if (side == InputSide.Left)
        {
            float t = Mathf.Clamp01(x / _halfWidth);
            leftCat.MoveNormalized(t, deltaX);
        }
        else
        {
            float t = Mathf.Clamp01((x - _midX) / _halfWidth);
            rightCat.MoveNormalized(t, deltaX);
        }
    }
}
public enum InputSide
{
    None,
    Left,
    Right
}

